Below is a JavaScript function that checks if any number in the input array is a prime number. This function uses a helper function `isPrime` to check if a number is prime.

```javascript
function isPrime(n) {
  if (n <= 1) return false;
  if (n === 2) return true;
  if (n % 2 === 0) return false;

  // Only need to check up to the square root of n
  for (let i = 3; i * i <= n; i += 2) {
    if (n % i === 0) return false;
  }
  return true;
}

function checkPrimes(numbers) {
  if (!Array.isArray(numbers) || numbers.length!== 5) {
    console.error("Input must be an array of 5 numbers.");
    return;
  }

  numbers.forEach((num) => {
    if (typeof num!== 'number' ||!Number.isInteger(num)) {
      console.error("All elements in the array must be integers.");
      return;
    }

    if (isPrime(num)) {
      console.log(`Number ${num} is a prime number.`);
    }
  });
}

